+// ============================================================================
+// Module Name Mappings (Python 2 -> Python 3)
+// ============================================================================
+
+/// Mapping of Python 2 module names to Python 3
+pub const NAME_MAPPING = std.StaticStringMap([]const u8).initComptime(.{
