+    .{ "__builtin__", "builtins" },
+    .{ "copy_reg", "copyreg" },
+    .{ "Queue", "queue" },
+    .{ "SocketServer", "socketserver" },
+    .{ "ConfigParser", "configparser" },
+    .{ "repr", "reprlib" },
